import 'dart:convert';
enum EditorialState { draft, reviewed, verified, outdated }
class EditorialItem {const EditorialItem({required this.id,required this.title,required this.author,required this.version,required this.created,required this.reviewed,required this.state,required this.sources,required this.notes,required this.nextReview});final String id,title,author,version,notes;final DateTime created,reviewed,nextReview;final EditorialState state;final List<String> sources;bool isExpired(DateTime now)=>nextReview.isBefore(DateTime(now.year,now.month,now.day));}
class EditorialManifestReader {const EditorialManifestReader();List<EditorialItem> parse(String source,{DateTime? now}){final root=jsonDecode(source) as Map<String,dynamic>;if(root['schemaVersion']!=1)throw const FormatException('Manifiesto editorial incompatible.');return (root['items'] as List).cast<Map<String,dynamic>>().map((item){String requiredText(String key){final value=item[key];if(value is! String||value.trim().isEmpty)throw FormatException('$key ausente en ${item['id']}');return value;}final sources=(item['sources'] as List).cast<String>();if(sources.any((value)=>value.trim().isEmpty))throw const FormatException('Fuente vacía.');final quotes=(item['textualQuotes'] as List? ?? const []).cast<Map<String,dynamic>>();if(quotes.any((quote)=>(quote['source'] as String? ?? '').trim().isEmpty))throw const FormatException('Cita textual sin fuente.');if(item['currentClaims']==true&&(item['reviewed'] as String? ?? '').isEmpty)throw const FormatException('Afirmación actual sin revisión.');final next=DateTime.parse(requiredText('nextReview'));final declared=requiredText('status');final state=next.isBefore(now??DateTime.now())?EditorialState.outdated:switch(declared){'borrador'=>EditorialState.draft,'revisado'=>EditorialState.reviewed,'verificado'=>EditorialState.verified,'desactualizado'=>EditorialState.outdated,_=>throw FormatException('Estado inválido: $declared')};return EditorialItem(id:requiredText('id'),title:requiredText('title'),author:requiredText('author'),version:requiredText('version'),created:DateTime.parse(requiredText('created')),reviewed:DateTime.parse(requiredText('reviewed')),state:state,sources:sources,notes:requiredText('notes'),nextReview:next);}).toList();}}
